from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema import Message
from markitdown import MarkItDown

class MarkItDownParser(Component):
    display_name = "MarkItDown PDF Parser"
    description = "Mengekstrak file PDF kompleks menjadi Markdown menggunakan Microsoft MarkItDown."
    icon = "file-text"

    inputs = [
        MessageTextInput(
            name="file_path",
            display_name="PDF File Path",
            info="Masukkan path absolut dari file PDF (contoh: D:\\Kuliah S2\\...).",
            required=True,
        )
    ]

    outputs = [
        Output(display_name="Markdown Text", name="text_output", method="build_output"),
    ]

    # Mengubah return type menjadi Message untuk kompatibilitas arsitektur Langflow V1
    def build_output(self) -> Message:
        try:
            md = MarkItDown()
            result = md.convert(self.file_path)
            # Membungkus string mentah ke dalam representasi objek Message
            return Message(text=result.text_content)
        except Exception as e:
            return Message(text=f"Error extraction gagal: {str(e)}")
